const content = $input.first().json.choices?.[0]?.message?.content || '';
let json;
try {
  json = JSON.parse(content);
} catch (e) {
  // Fallback defaults if Groq returned invalid JSON
  json = { types: 'cafe,restaurant', radius: 1500, language: 'en' };
}
// Coerce types to a string
if (Array.isArray(json.types)) json.types = json.types.join(',');
if (!json.types) json.types = 'cafe,restaurant';
if (!json.radius) json.radius = 1500;
if (!json.language) json.language = 'en';
return [{ json: { searchParams: json, context: $('Fetch Context').item.json.context } }];

const olaResponse = $input.first().json;
const status = olaResponse.status;
const predictions = Array.isArray(olaResponse.predictions) ? olaResponse.predictions : [];
const context = $('Parse Search Params').item.json.context;

if (status === 'zero_results' || predictions.length === 0) {
  return [{ json: { context, places: [], zeroResults: true } }];
}

const places = predictions.slice(0, 20).map(p => ({
  place_id: p.place_id,
  name: p.structured_formatting?.main_text || p.description || 'Unnamed',
  address: p.structured_formatting?.secondary_text || p.description || '',
  description: p.description || '',
  types: p.types || [],
  distance_meters: p.distance_meters || 0,
  lat: p.geometry?.location?.lat || p.geometry?.location?.latitude || null,
  lng: p.geometry?.location?.lng || p.geometry?.location?.longitude || null,
}));

return [{ json: { context, places, zeroResults: false } }];

