const content = $input.first().json.choices?.[0]?.message?.content || '';
const normalized = $('Normalize Places').item.json;
const places = normalized.places;
const placesById = new Map(places.map(p => [p.place_id, p]));

let ranked = [];
try {
  const parsed = JSON.parse(content);
  if (Array.isArray(parsed?.recommendations)) ranked = parsed.recommendations;
  else if (Array.isArray(parsed)) ranked = parsed;
} catch (e) {
  ranked = [];
}

function buildMapsUrl(p) {
  if (p.lat != null && p.lng != null) {
    return `https://www.google.com/maps/search/?api=1&query=${p.lat},${p.lng}`;
  }
  return `https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(p.name + ' ' + p.address)}`;
}

const spots = [];
for (const r of ranked) {
  const p = placesById.get(r.placeId);
  if (!p) continue;
  spots.push({
    name: p.name,
    address: p.address,
    distanceMeters: p.distance_meters,
    mapsUrl: buildMapsUrl(p),
    reason: r.reason,
  });
  if (spots.length >= 5) break;
}

// Fallback: if Groq returned nothing usable, top 5 places with generic reasons
if (spots.length === 0 && places.length > 0) {
  for (const p of places.slice(0, 5)) {
    spots.push({
      name: p.name,
      address: p.address,
      distanceMeters: p.distance_meters,
      mapsUrl: buildMapsUrl(p),
      reason: `A nearby spot worth checking out (${p.distance_meters}m away).`,
    });
  }
}

return [{ json: { success: true, spots } }];
